"""Tests for cmd_render wiring - Phase 5: DB → markdown renderer."""

from __future__ import annotations

import shutil
import sqlite3
from pathlib import Path

import pytest

from codeatlas.explore_codebase import db
from codeatlas.explore_codebase.cli import cmd_render


BANNER = (
    "<!-- Generated by /explore-codebase. Hand edits will be overwritten. "
    "Notes belong in .claude/codeatlas/notes/ -->"
)


# ---------------------------------------------------------------------------
# Fixtures and helpers
# ---------------------------------------------------------------------------


def _args(project: Path, *, base_sha: str | None = None, since: str | None = None):
    import argparse

    return argparse.Namespace(project_root=str(project), base_sha=base_sha, since=since)


def _open_db(project: Path) -> sqlite3.Connection:
    return sqlite3.connect(project / ".claude/codeatlas" / "codebase.db")


def _maps_dir(project: Path) -> Path:
    return project / ".claude/codeatlas" / "maps"


def _context_dir(project: Path) -> Path:
    return project / ".claude/codeatlas" / "context"


def _section(body: str, start_marker: str, end_marker: str) -> str:
    """Slice body between two heading markers (start inclusive, end exclusive)."""
    start = body.find(start_marker)
    end = body.find(end_marker, start)
    if start == -1:
        return ""
    if end == -1:
        return body[start:]
    return body[start:end]


def _insert_file(conn: sqlite3.Connection, path: str, sha: str = "deadbeef") -> int:
    cur = conn.execute(
        "INSERT INTO files (path, sha, language, last_parsed_at) VALUES (?, ?, ?, ?)",
        (path, sha, "python", "2026-01-01T00:00:00"),
    )
    conn.commit()
    assert cur.lastrowid is not None
    return cur.lastrowid


def _insert_symbol(
    conn: sqlite3.Connection,
    file_id: int,
    name: str,
    kind: str = "function",
    line: int = 1,
    scope: str | None = None,
) -> int:
    cur = conn.execute(
        "INSERT INTO symbols (file_id, kind, name, scope, line) VALUES (?, ?, ?, ?, ?)",
        (file_id, kind, name, scope, line),
    )
    conn.commit()
    assert cur.lastrowid is not None
    return cur.lastrowid


def _insert_edge(conn: sqlite3.Connection, src_id: int, dst_id: int, kind: str) -> None:
    conn.execute(
        "INSERT INTO edges (src_id, dst_id, kind) VALUES (?, ?, ?)",
        (src_id, dst_id, kind),
    )
    conn.commit()


@pytest.fixture
def project(tmp_path: Path) -> Path:
    """A project root with the DB pre-initialised."""
    db_path = tmp_path / ".claude/codeatlas" / "codebase.db"
    conn = db.init(db_path)
    conn.close()
    return tmp_path


@pytest.fixture
def populated_project(project: Path) -> Path:
    """A project DB with two modules (pkg_a, pkg_b), symbols, and edges."""
    conn = _open_db(project)
    try:
        # pkg_a: two files, two functions, one class.
        f_a1 = _insert_file(conn, "pkg_a/alpha.py", "sha_a1")
        f_a2 = _insert_file(conn, "pkg_a/beta.py", "sha_a2")
        s_alpha_func = _insert_symbol(conn, f_a1, "alpha_func", "function", line=10)
        # AlphaClass is part of pkg_a's symbol set but no edges point at it.
        _insert_symbol(conn, f_a1, "AlphaClass", "class", line=20)
        s_beta_func = _insert_symbol(conn, f_a2, "beta_func", "function", line=5)

        # pkg_b: one file, one function, one variable.
        f_b1 = _insert_file(conn, "pkg_b/gamma.py", "sha_b1")
        s_gamma_func = _insert_symbol(conn, f_b1, "gamma_func", "function", line=3)
        s_gamma_var = _insert_symbol(conn, f_b1, "GAMMA_VAR", "variable", line=1)

        # Edges:
        # gamma_func calls alpha_func (cross-module call into pkg_a)
        # alpha_func calls beta_func (intra-module call inside pkg_a)
        # gamma.py imports alpha.py (resolved via gamma_var → alpha_func)
        _insert_edge(conn, s_gamma_func, s_alpha_func, "calls")
        _insert_edge(conn, s_alpha_func, s_beta_func, "calls")
        _insert_edge(conn, s_gamma_var, s_alpha_func, "imports")
    finally:
        conn.close()
    return project


