def test_recent_changes_md_placeholder_when_since_absent(populated_project: Path):
    """Without --since the recent-changes map is a stub."""
    cmd_render(_args(populated_project))
    body = (_maps_dir(populated_project) / "recent-changes.md").read_text(
        encoding="utf-8"
    )
    assert "No --since provided" in body
    assert "recent-changes map unavailable" in body


def test_recent_changes_md_lists_changed_files_with_since(project: Path):
    """With --since and a mock git_log_fn, changed files + 1-hop deps appear."""
    conn = _open_db(project)
    try:
        f_a = _insert_file(conn, "pkg/changed.py", sha="sa")
        f_b = _insert_file(conn, "pkg/dep.py", sha="sb")
        s_a = _insert_symbol(conn, f_a, "changed_fn", "function", line=1)
        s_b = _insert_symbol(conn, f_b, "dep_fn", "function", line=1)
        _insert_edge(conn, s_a, s_b, "calls")
    finally:
        conn.close()

    # Inject a fake git_log function that "returns" pkg/changed.py.
    from codeatlas.explore_codebase import render

    fake_git = lambda root, since: ["pkg/changed.py"]  # noqa: E731
    rc = render.run(
        sqlite3.connect(project / ".claude/codeatlas" / "codebase.db"),
        project,
        base_sha=None,
        since="HEAD~1",
        git_log_fn=fake_git,
    )
    assert rc == 0
    body = (_maps_dir(project) / "recent-changes.md").read_text(encoding="utf-8")
    assert "pkg/changed.py" in body
    assert "pkg/dep.py" in body, "1-hop dependent must appear in recent-changes.md"


def test_recent_changes_md_ignores_files_not_in_db(project: Path):
    """Doom-path: git reports a tracked + an untracked file → only tracked appears."""
    conn = _open_db(project)
    try:
        _insert_file(conn, "tracked.py", sha="st")
    finally:
        conn.close()

    from codeatlas.explore_codebase import render

    fake_git = lambda root, since: ["tracked.py", "untracked.py"]  # noqa: E731
    rc = render.run(
        sqlite3.connect(project / ".claude/codeatlas" / "codebase.db"),
        project,
        base_sha=None,
        since="HEAD~1",
        git_log_fn=fake_git,
    )
    assert rc == 0
    body = (_maps_dir(project) / "recent-changes.md").read_text(encoding="utf-8")
    # Tracked file shows up, untracked is filtered out.
    assert "tracked.py" in body
    assert "untracked.py" not in body, (
        "files outside the DB must not produce a section in recent-changes"
    )


def test_recent_changes_md_empty_git_log(project: Path):
    """Doom-path: --since with no matching files → recent-changes renders empty cleanly."""
    from codeatlas.explore_codebase import render

    fake_git = lambda root, since: []  # noqa: E731
    rc = render.run(
        sqlite3.connect(project / ".claude/codeatlas" / "codebase.db"),
        project,
        base_sha=None,
        since="HEAD~1",
        git_log_fn=fake_git,
    )
    assert rc == 0
    body = (_maps_dir(project) / "recent-changes.md").read_text(encoding="utf-8")
    # No files came back from git → file still rendered with banner + header.
    assert body.startswith(BANNER)


